<span class="line"><span style="color:#61AFEF;">git</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">merge</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">lab</span><span style="color:#ABB2BF;">(</span><span style="color:#61AFEF;">x-1</span><span style="color:#ABB2BF;">)</span></span>
